using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int main(){
	int n,a,b,dp[101][100001];
	cin>>n;
	memset(dp,128,sizeof(dp));
	dp[0][50000]=0;
	for(int i=1;i<=n;i++){
		cin>>a>>b;
		for(int j=1;j<=100000;j++){
			if((j-a+b>=1)&&(j-a+b<=100000)){
				dp[i][j]=max(dp[i-1][j],dp[i-1][j-a+b]+a+b);
			}
			else{
				dp[i][j]=dp[i-1][j];
			}
		}
	}
	cout<<dp[n][50000];
	return 0;
}
